INSERT INTO `tbl_page` (`id`, `name`, `body`) VALUES
(1, 'About Us', '<p data-start=\"129\" data-end=\"461\"><strong>Azad&rsquo;s Techno Algo Live Hub</strong> is a modern technology and research-based learning platform dedicated to practical knowledge and real-world skill development. We provide tutorials, technical articles, and project guides in C, C++, Java, Web Development, Algorithms, Competitive Programming, Machine Learning, Deep Learning, AI, and IoT.</p>\r\n<p data-start=\"463\" data-end=\"746\">Our goal is to make <em>complex technical concepts simple, structured, and easy to apply.</em> Through hands-on projects, problem-solving approaches, and research-driven content, we help students, professionals, and tech enthusiasts strengthen their coding, analytical, and innovation skills.</p>\r\n<p data-start=\"748\" data-end=\"783\" data-is-last-node=\"\" data-is-only-node=\"\"><strong data-start=\"748\" data-end=\"783\" data-is-last-node=\"\">Explore. Learn. Innovate. Grow.</strong></p>'),
(2, 'Privacy', '<p><span style=\"font-family: arial, helvetica, sans-serif;\">At <strong data-start=\"186\" data-end=\"217\">Azad&rsquo;s Techno Algo Live Hub</strong>, we value your privacy and are committed to protecting your personal information. Our mission is to provide high-quality content in <strong data-start=\"350\" data-end=\"399\">Computer Science, programming, and technology</strong>, while ensuring that your data remains secure and confidential.</span></p>\n<h3 style=\"text-align: justify;\" data-start=\"467\" data-end=\"498\"><span style=\"font-family: arial, helvetica, sans-serif;\">1. Information We Collect</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">We may collect certain information to improve your experience on our website, including:</span></p>\n<ul style=\"text-align: justify;\" data-start=\"590\" data-end=\"1024\">\n<li data-start=\"590\" data-end=\"751\"><span style=\"font-family: arial, helvetica, sans-serif;\"><strong data-start=\"592\" data-end=\"616\">Personal information</strong>: Name, email address, or other details you provide voluntarily, for example, when subscribing to our newsletter or submitting forms.</span></li>\n<li data-start=\"752\" data-end=\"902\"><span style=\"font-family: arial, helvetica, sans-serif;\"><strong data-start=\"754\" data-end=\"775\">Usage information</strong>: Information about how you navigate and interact with our website, including pages visited, time spent on pages, and clicks.</span></li>\n<li data-start=\"903\" data-end=\"1024\"><span style=\"font-family: arial, helvetica, sans-serif;\"><strong data-start=\"905\" data-end=\"934\">Cookies and tracking data</strong>: Small files stored on your device to enhance user experience and remember preferences.</span></li>\n</ul>\n<h3 style=\"text-align: justify;\" data-start=\"1026\" data-end=\"1062\"><span style=\"font-family: arial, helvetica, sans-serif;\">2. How We Use Your Information</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">The information collected is used only for specific purposes:</span></p>\n<ul style=\"text-align: justify;\" data-start=\"1127\" data-end=\"1373\">\n<li data-start=\"1127\" data-end=\"1215\"><span style=\"font-family: arial, helvetica, sans-serif;\">To provide updates, newsletters, and notifications about new tutorials or resources.</span></li>\n<li data-start=\"1216\" data-end=\"1305\"><span style=\"font-family: arial, helvetica, sans-serif;\">To improve our website content, structure, and performance based on user interaction.</span></li>\n<li data-start=\"1306\" data-end=\"1373\"><span style=\"font-family: arial, helvetica, sans-serif;\">To communicate with you when responding to queries or requests.</span></li>\n</ul>\n<h3 style=\"text-align: justify;\" data-start=\"1375\" data-end=\"1418\"><span style=\"font-family: arial, helvetica, sans-serif;\">3. Information Sharing and Disclosure</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">We respect your trust and <strong data-start=\"1445\" data-end=\"1525\">do not share, sell, or distribute your personal information to third parties</strong>. Your information remains strictly confidential unless required by law or to protect the rights and safety of our website.</span></p>\n<h3 style=\"text-align: justify;\" data-start=\"1652\" data-end=\"1681\"><span style=\"font-family: arial, helvetica, sans-serif;\">4. Cookies and Tracking</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">Our website may use cookies to enhance functionality, remember user preferences, and analyze site traffic. Cookies are safe and <strong data-start=\"1810\" data-end=\"1859\">do not contain sensitive personal information</strong>. You can disable cookies in your browser settings if you prefer, though some features may be limited.</span></p>\n<h3 style=\"text-align: justify;\" data-start=\"1965\" data-end=\"1991\"><span style=\"font-family: arial, helvetica, sans-serif;\">5. Security Measures</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">We implement reasonable technical and administrative measures to protect your personal information from unauthorized access, disclosure, or misuse. While no website can guarantee complete security, we continually review and improve our safeguards.</span></p>\n<h3 style=\"text-align: justify;\" data-start=\"2243\" data-end=\"2263\"><span style=\"font-family: arial, helvetica, sans-serif;\">6. Your Rights</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">You have the right to:</span></p>\n<ul style=\"text-align: justify;\" data-start=\"2289\" data-end=\"2469\">\n<li data-start=\"2289\" data-end=\"2346\"><span style=\"font-family: arial, helvetica, sans-serif;\">Request information about the data we hold about you.</span></li>\n<li data-start=\"2347\" data-end=\"2411\"><span style=\"font-family: arial, helvetica, sans-serif;\">Ask for corrections or updates to your personal information.</span></li>\n<li data-start=\"2412\" data-end=\"2469\"><span style=\"font-family: arial, helvetica, sans-serif;\">Opt out of newsletters or communications at any time.</span></li>\n</ul>\n<h3 style=\"text-align: justify;\" data-start=\"2471\" data-end=\"2502\"><span style=\"font-family: arial, helvetica, sans-serif;\">7. Changes to This Policy</span></h3>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">We may update our privacy policy occasionally to reflect changes in regulations or our website practices. Updates will be posted on this page, and we encourage users to review it periodically.</span></p>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">By using <strong data-start=\"2708\" data-end=\"2739\">Azad&rsquo;s Techno Algo Live Hub</strong>, you agree to the terms outlined in this Privacy Policy. Your trust is important to us, and we are committed to maintaining transparency, security, and a safe environment for learning.</span></p>\n<p><span style=\"font-family: arial, helvetica, sans-serif;\">\"</span></p>'),
(3, 'DMCA', '<p><strong style=\"font-size: 10px;\" data-start=\"267\" data-end=\"300\">DMCA Notice &amp; Takedown Policy</strong></p>\r\n<p data-start=\"304\" data-end=\"582\">This website, <strong data-start=\"318\" data-end=\"349\">Azad&rsquo;s Techno Algo Live Hub</strong>, respects the intellectual property rights of others and expects its users to do the same. In accordance with the <strong data-start=\"464\" data-end=\"507\">Digital Millennium Copyright Act (DMCA)</strong>, we respond promptly to claims of copyright infringement reported to us.</p>\r\n<h3 data-start=\"584\" data-end=\"617\">How to Submit a DMCA Notice</h3>\r\n<p data-start=\"618\" data-end=\"769\">If you believe that your copyrighted work has been copied in a way that constitutes copyright infringement, please provide the following information:</p>\r\n<ol data-start=\"770\" data-end=\"1233\">\r\n<li data-start=\"770\" data-end=\"842\">\r\n<p data-start=\"773\" data-end=\"842\">A description of the copyrighted work you claim has been infringed.</p>\r\n</li>\r\n<li data-start=\"843\" data-end=\"928\">\r\n<p data-start=\"846\" data-end=\"928\">The exact URL or location on our website where the infringing material is found.</p>\r\n</li>\r\n<li data-start=\"929\" data-end=\"995\">\r\n<p data-start=\"932\" data-end=\"995\">Your full name, address, telephone number, and email address.</p>\r\n</li>\r\n<li data-start=\"996\" data-end=\"1117\">\r\n<p data-start=\"999\" data-end=\"1117\">A statement that you have a good faith belief that the use of the material is not authorized by the copyright owner.</p>\r\n</li>\r\n<li data-start=\"1118\" data-end=\"1189\">\r\n<p data-start=\"1121\" data-end=\"1189\">A statement that the information in your notification is accurate.</p>\r\n</li>\r\n<li data-start=\"1190\" data-end=\"1233\">\r\n<p data-start=\"1193\" data-end=\"1233\">Your electronic or physical signature.</p>\r\n</li>\r\n</ol>\r\n<h3 data-start=\"1235\" data-end=\"1274\">Where to Send Your DMCA Complaint</h3>\r\n<p data-start=\"1275\" data-end=\"1343\"><strong data-start=\"1278\" data-end=\"1288\">&nbsp; Email:</strong>&nbsp;azadcse14716<a class=\"decorated-link cursor-pointer\" rel=\"noopener\" data-start=\"1289\" data-end=\"1303\">@email.com</a><br data-start=\"1303\" data-end=\"1306\" /><strong data-start=\"1309\" data-end=\"1321\">&nbsp;Website:</strong>&nbsp;www.azadstechnoalgolivehub.com</p>\r\n<p data-start=\"1345\" data-end=\"1484\">Upon receiving a valid DMCA notice, we will review it promptly and remove or disable access to the infringing content as required by law.</p>');

